#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y, R; scanf("%lld %lld %lld", &X, &Y, &R);
        long long extra = R / 30LL; // each extra stick gives 30 rupees
        long long total = X + extra;
        long long plates = (total + Y - 1) / Y; // ceiling division
        printf("%lld\n", plates);
    }
    return 0;
}

